define("mod_collabmatch/move_submitter",["core/ajax","core/notification","core/str"],function(Ajax,Notification,Str){"use strict";return{init:function(cmid,formid){var form=document.getElementById(formid);if(!form){return}var submitButton=form.querySelector('button[type="submit"], input[type="submit"]');form.addEventListener("submit",function(e){e.preventDefault();var itemField=form.querySelector('[name="item"]'),zoneField=form.querySelector('[name="zone"]'),item=itemField?String(itemField.value||"").trim():"",zone=zoneField?String(zoneField.value||"").trim():"";if(!item||!zone){Notification.alert("CollabMatch",Str.get_string("jsitemzonebothrequired","mod_collabmatch"),Str.get_string("ok","moodle"));return}if(submitButton&&submitButton.disabled){return}if(submitButton){submitButton.disabled=true}Ajax.call([{methodname:"mod_collabmatch_submit_move",args:{cmid:cmid,item:item,zone:zone}}])[0].then(function(response){if(response&&response.success){window.location.reload();return}if(submitButton){submitButton.disabled=false}return Promise.all([Str.get_string("pluginname","mod_collabmatch"),Str.get_string("jsmovesubmitfailed","mod_collabmatch"),Str.get_string("ok","moodle")]).then(function(strings){Notification.alert(strings[0],strings[1],strings[2])})}).catch(function(error){if(submitButton){submitButton.disabled=false}Notification.exception(error)})})}}});